import re, math, fractions

def normalize_answer(text: str) -> str:
    text = text.strip().lower().replace(" ", "")
    # Remove trailing .0 from integers
    text = re.sub(r"(\.\d*?)0+$", r"\1", text)
    text = re.sub(r"\.$ ", "", text)
    try:
        value = float(text)
        if value == int(value): return str(int(value))
        return str(round(value, 6))
    except ValueError: pass
    try:
        value = fractions.Fraction(text)
        return str(value)
    except (ValueError, ZeroDivisionError): pass
    return text

def math_reward(completion: str, ground_truth: str) -> float:
    pred = extract_answer(completion)
    if pred is None: return 0.0
    return 1.0 if normalize_answer(pred) == normalize_answer(ground_truth) else 0.0

from pydantic import BaseModel, ValidationError
import json, re

class StructuredOutput(BaseModel):
    reasoning: str
    answer: str
    confidence: float
    sources: list

def structured_output_reward(completion: str, ground_truth_answer: str) -> float:
    json_match = re.search(r"```json\n(.*?)```", completion, re.DOTALL)
    if not json_match:
        json_match = re.search(r"\{.*?\}", completion, re.DOTALL)
    if not json_match: return 0.0
    try:
        data = json.loads(json_match.group(0))
        obj = StructuredOutput(**data)
    except (json.JSONDecodeError, ValidationError):
        return 0.1
    answer_correct = normalize_answer(obj.answer) == normalize_answer(ground_truth_answer)
    return 0.3 + 0.7 * float(answer_correct)

from dataclasses import dataclass

@dataclass
class RewardSpec:
    weight: float
    fn: object  # callable

def composite_reward(completion: str, metadata: dict,
                     specs: list) -> float:
    total_weight = sum(s.weight for s in specs)
    total_reward = 0.0
    for spec in specs:
        r = spec.fn(completion, metadata)
        total_reward += spec.weight * r
    return total_reward / total_weight

